var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"침식체가 나타난 것치곤 너무 잠잠하다 싶더라니…","JPN":"侵食体が現れた割に静か過ぎると思ったら……","ENG":"For something that was supposed to be a C.O. outbreak, it felt way too quiet...","TWN":"侵蝕體出現得太安靜，我就覺得奇怪……"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"저 벌레 알 같은 게 침식체를 뿜어내는 거였다고?","JPN":"あの虫の卵みたいなものが侵食体を生み出してたの？","ENG":"Those bug-egg-looking things are what spawned a C.O.?","TWN":"原來是那些像蟲卵一樣的東西在釋放侵蝕體？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ADMIN_OMEN_NPC_NULL","text":{"KOREA":"맞습니다.","JPN":"そうです。","ENG":"That is correct.","TWN":"沒錯。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ADMIN_OMEN_NPC_NULL","text":{"KOREA":"게다가, 이 알의 침식파는 침입자들이 난동을 부렸을 때의 시그니처 파형과 일치합니다.","JPN":"それに、この卵の侵食波は侵入者たちが騒ぎを起こした時のシグネチャー波形と一致しています。","ENG":"On top of that, the Corruption rays from these eggs match the signature waveform detected when the intruders went on their rampage.","TWN":"而且這些卵的侵蝕波，與入侵者暴動時的信號波形一致。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ADMIN_OMEN_NPC_NULL","text":{"KOREA":"이런 것들이 구역마다 다수 발견됐어요.","JPN":"各区域から同じものが多数発見されました。","ENG":"We found multiple clusters like this in each district.","TWN":"在各個區域都發現大量這種東西。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"상부에서 추정한 침입자들 머릿수랑 얼추 비슷하네.","JPN":"上層部が推定した侵入者の数とほぼ同じか。","ENG":"That is roughly the same number as the intruders headquarters estimated.","TWN":"和上級推測的入侵者人數大致相符。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"네? 설마 저 알이 원래는 사람이었단 말인가요?","JPN":"え？　まさかあの卵、元々は人間だったってことですか？","ENG":"What? Are you saying those eggs were originally people?","TWN":"什麼？難道那些卵原本是人嗎？"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"뭐, 아직은 가정일 뿐이지만.","JPN":"まだ仮説にすぎないけどね。","ENG":"Well, it is still just a hypothesis for now.","TWN":"嗯，目前還只是推測而已。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"위험 수준은 어때?","JPN":"危険度はどう？","ENG":"What's the danger level?","TWN":"危險等級如何？"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"ADMIN_OMEN_NPC_NULL","text":{"KOREA":"불행 중 다행이랄까… 폭발체나 부화를 앞둔 침식체 알은 아니라 위험도는 낮습니다.","JPN":"不幸中の幸いというか……爆発タイプや孵化寸前の卵ではないので、危険度は低いほうです。","ENG":"If there's a silver lining... they're not explosive, and they're not C.O. eggs about to hatch. The risk level is low.","TWN":"該說不幸中的大幸嗎……這些並不是爆裂體，也不是即將孵化的侵蝕體卵，危險程度很低。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"ADMIN_OMEN_NPC_NULL","text":{"KOREA":"샹그릴라 생태에서 발견되는 동면 개체들과 유사해요.","JPN":"シャングリラ生態系で見つかる冬眠個体と類似しています。","ENG":"They resemble dormant specimens found in the Shangri-La ecosystem.","TWN":"和香格里拉生態中發現的冬眠個體相似。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"샹그릴라 생태가 뭐죠?","JPN":"シャングリラ生態系とは何でしょうか？","ENG":"The Shangri-La ecosystem?","TWN":"什麼是香格里拉生態？"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"ADMIN_OMEN_NPC_NULL","text":{"KOREA":"민하 님, 이분은…?","JPN":"ミウ様、こちらの方は……？","ENG":"Ms. Minha, who is this...?","TWN":"敏荷，這位是……？"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"외부 협력인원이야. 임시로 같이 다니고 있어.","JPN":"外部からの協力者。臨時で同行してる。","ENG":"She is an external collaborator. We are working together temporarily.","TWN":"外部協力人員。暫時一起行動。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"외부 협력인원은 표현이 좀 딱딱한데, 파트너는 어때요?","JPN":"外部からの協力者という呼び方はやや味気ないので……パートナーはどうですか？","ENG":"\\"External collaborator\\" sounds a bit stiff. How about \\"partner\\"?","TWN":"外部協力人員這個說法有點生硬，叫夥伴怎麼樣？"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"…파트너야.","JPN":"……パートナー。","ENG":"...Partner.","TWN":"……夥伴。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"ADMIN_OMEN_NPC_NULL","text":{"KOREA":"아하.","JPN":"なるほど。","ENG":"Ah, I see.","TWN":"啊哈。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"아무튼, 파트너한테는 기밀 조항 지킬 필요 없으니 그냥 다 설명해줘.","JPN":"とにかく、パートナーに対して機密条項を守る必要はないから、全部説明してあげて。","ENG":"Anyway, you do not need to enforce confidentiality clauses with my partner. Just explain everything.","TWN":"總之，對夥伴就不用遵守機密條款了。直接全部說明吧。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"ADMIN_OMEN_NPC_NULL","text":{"KOREA":"샹그릴라는 챔버 대균열에 위치한 극저온 환경의 이면세계입니다.","JPN":"シャングリラはチェンバー大亀裂に位置する極低温環境の裏世界です。","ENG":"Shangri-La is a cryogenic Counterside located within Chamber's Grand Dimension Crevice.","TWN":"香格里拉是位於強巴大峽谷中極低溫環境的異界。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ADMIN_OMEN_NPC_NULL","text":{"KOREA":"그곳에 서식하는 침식체들은 특별한 이유가 없으면 활동을 정지하고 동면 상태에 들어가는 특징이 있죠.","JPN":"そこに生息する侵食体は、特別な理由がないと活動を停止し、冬眠状態に入るという特徴があります。","ENG":"C.O.s that inhabit it typically cease activity and enter dormancy unless there is a special reason not to.","TWN":"棲息於那裡的侵蝕體，若非特殊原因，會停止活動並進入冬眠狀態。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"그러니까, 이 알들이 잠들어 있다는 뜻인가요?","JPN":"つまり、この卵は眠っているということですか？","ENG":"So these eggs are asleep?","TWN":"所以是這些卵在沉睡的意思嗎？"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"ADMIN_OMEN_NPC_NULL","text":{"KOREA":"저희 판단은 그렇습니다. 거기에 더해 이 알집은 굉장히 견고해요.","JPN":"私たちはそう判断しています。加えてこの卵嚢は非常に堅固にできています。","ENG":"That is our assessment. On top of that, these egg sacs are extremely durable.","TWN":"我們是這樣判斷的。而且這些卵囊相當堅固。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"ADMIN_OMEN_NPC_NULL","text":{"KOREA":"내부를 직접 확인하려 했지만 저희가 가진 장비로도 뚫을 수 없었어요.","JPN":"内部を直接確認しようとしましたが、私たちの装備では破ることができませんでした。","ENG":"We tried to inspect the interior directly, but even our equipment couldn't penetrate them.","TWN":"我們嘗試直接確認內部狀況，但就連現有設備也無法突破。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"3종 갑피도 뚫는 해체 드릴이 안 먹힐 정도라고?","JPN":"第3種の甲皮も貫く解体ドリルも効かないってどれだけ固いわけ？","ENG":"Even a dismantling drill that pierces Category 3 armor couldn't get through?","TWN":"連能鑽穿第3類外殼的解體鑽都沒有用？"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"그 정도로 단단하게 만들어진 이유가 있을까요?","JPN":"どうしてそんなに固く作られているんでしょうか？","ENG":"Is there a reason they were made that tough?","TWN":"為什麼要製作得這麼堅硬呢？"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"ADMIN_OMEN_NPC_NULL","text":{"KOREA":"외부로부터 자신을 지키려는 거죠. 이 정도면 핵무기가 직격으로 떨어져도 멀쩡할 겁니다.","JPN":"外部から自分を守るためでしょう。この程度なら、核兵器が直撃しても傷一つつかないと思います。","ENG":"To protect themselves from external threats. At this level, they'd remain intact even if a nuclear weapon hit them directly.","TWN":"那是為了保護自己不受外界影響。這種程度的話，就算核武正面命中也能毫髮無傷。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"스스로를 지킨다고? 대체 뭘로부터?","JPN":"自分を守る？　いったい何から？","ENG":"Protect themselves? From what, exactly?","TWN":"保護自己？到底是防禦什麼？"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"ADMIN_OMEN_NPC_NULL","text":{"KOREA":"그건 아마-","JPN":"おそらく……","ENG":"That would likely be...","TWN":"那恐怕是—"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"ADMIN_OMEN_NPC_NULL","text":{"KOREA":"자신들도 감당 못할 정도의 재난이 이곳에서 벌어진다던가…","JPN":"彼らも耐えきれないほどの災害が、ここで起きるとか……","ENG":"A disaster so severe that even they could not withstand it, erupting right here...","TWN":"將會在這裡發生，連它們自己都無法承受的災難……"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};